using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations ---

var notebook = new Notebook();

[Description("Search the web for information on a query. Returns a list of result snippets.")]
string WebSearch([Description("The search query")] string query)
{
    Console.WriteLine($"  🔍 Searching the web for: \"{query}\"");

    // Simulated search results keyed on topic keywords.
    var results = new Dictionary<string, string[]>(StringComparer.OrdinalIgnoreCase)
    {
        ["quantum computing"] =
        [
            "Quantum computing uses qubits that can exist in superposition, enabling parallel computation. " +
            "Companies like IBM, Google, and Microsoft are investing heavily in the technology.",
            "In 2024 IBM unveiled its 1,121-qubit Condor processor. Google's Willow chip demonstrated " +
            "quantum error correction below the surface-code threshold for the first time.",
            "Practical applications include drug discovery, cryptography, optimization problems, and " +
            "materials science. Experts estimate fault-tolerant quantum computers are 5-10 years away."
        ],
        ["artificial intelligence"] =
        [
            "AI has seen rapid advances with large language models (LLMs) like GPT-4, Claude, and Gemini " +
            "transforming how people interact with technology.",
            "Key areas of AI research include reasoning, multimodal understanding, AI safety, and agentic " +
            "workflows where AI systems can use tools and plan multi-step tasks.",
            "Concerns around AI include bias, job displacement, energy consumption, and the alignment problem — " +
            "ensuring AI systems act in accordance with human values."
        ],
        ["climate change"] =
        [
            "Global temperatures have risen approximately 1.1°C above pre-industrial levels. The Paris " +
            "Agreement aims to limit warming to 1.5°C.",
            "Renewable energy capacity surpassed 500 GW of new installations in 2023, with solar leading. " +
            "Battery storage costs have fallen 90% over the past decade.",
            "Major impacts include rising sea levels, more extreme weather events, biodiversity loss, and " +
            "threats to food security affecting billions of people worldwide."
        ]
    };

    // Try to match against known topics; fall back to a generic response.
    foreach (var (key, snippets) in results)
    {
        if (query.Contains(key, StringComparison.OrdinalIgnoreCase))
        {
            return string.Join("\n\n", snippets.Select((s, i) => $"[Result {i + 1}] {s}"));
        }
    }

    return $"[Result 1] General information about '{query}': This is an active area of research with " +
           "many recent developments. Further targeted searches may yield more specific results.";
}

[Description("Save a note to the research notebook for later reference.")]
string TakeNote(
    [Description("A short title for the note")] string title,
    [Description("The content of the note")] string content)
{
    notebook.AddNote(title, content);
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    return $"Note '{title}' saved successfully.";
}

[Description("Retrieve all notes from the research notebook.")]
string GetNotes()
{
    var notes = notebook.GetAllNotes();
    if (notes.Count == 0)
        return "The notebook is empty.";

    Console.WriteLine($"  📖 Reading notebook ({notes.Count} note(s))");
    return string.Join("\n\n", notes.Select((n, i) => $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
}

// --- Agent setup ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "no-key";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(TakeNote),
    AIFunctionFactory.Create(GetNotes)
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

var topic = args.Length > 0 ? string.Join(' ', args) : "quantum computing";

Console.WriteLine($"🤖 Research Agent Starting — topic: \"{topic}\"\n");

List<ChatMessage> messages =
[
    new(ChatRole.System,
        """
        You are a research agent. Your job is to research a topic thoroughly by using the
        available tools. Follow this workflow:
        1. Search the web for information on the topic (use multiple searches with different
           queries to get broad coverage).
        2. Take notes on the key findings from each search.
        3. After gathering enough information, read back your notes and produce a final
           comprehensive summary.
        Always use the tools — do not make up information. When you are done, present a
        final summary with sections for Overview, Key Findings, and Outlook.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
];

// --- Agent loop ---

Console.WriteLine("─── Agent working ───\n");

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n─── Research Complete ───\n");
Console.WriteLine(response.Text);

// --- Notebook helper ---

class Notebook
{
    private readonly List<Note> _notes = [];

    public void AddNote(string title, string content) =>
        _notes.Add(new Note(title, content));

    public IReadOnlyList<Note> GetAllNotes() => _notes;
}

record Note(string Title, string Content);

